import{_ as e,c as t,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"平台功能：核心指令與技能管理 | OpenSkills","description":"學習 OpenSkills 平台功能，掌握指令、安裝、列出、更新和刪除技能等核心操作，理解全域與專案管理的差異。","frontmatter":{"title":"平台功能：核心指令與技能管理 | OpenSkills","sidebarTitle":"掌握核心操作","subtitle":"平台功能：核心指令與技能管理 | OpenSkills","description":"學習 OpenSkills 平台功能，掌握指令、安裝、列出、更新和刪除技能等核心操作，理解全域與專案管理的差異。","order":2},"headers":[],"relativePath":"zh-tw/numman-ali/openskills/platforms/index.md","filePath":"zh-tw/numman-ali/openskills/platforms/index.md"}'),s={name:"zh-tw/numman-ali/openskills/platforms/index.md"};function i(o,a,d,n,h,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="平台功能" tabindex="-1">平台功能 <a class="header-anchor" href="#平台功能" aria-label="Permalink to &quot;平台功能&quot;">​</a></h1><p>本章節深入講解 OpenSkills CLI 的核心指令和技能管理功能，幫助你從「會用」到「精通」。</p><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前請確認</p><p>在學習本章節之前，請確保你已完成 <a href="./../start/">快速開始</a> 章節，特別是：</p><ul><li><a href="./../start/installation/">安裝 OpenSkills</a>：已成功安裝 OpenSkills CLI</li><li><a href="./../start/first-skill/">安裝第一個技能</a>：了解基本的技能安裝流程</li></ul></div><h2 id="本章內容" tabindex="-1">本章內容 <a class="header-anchor" href="#本章內容" aria-label="Permalink to &quot;本章內容&quot;">​</a></h2><p>本章節包含 6 個主題，涵蓋 OpenSkills 的所有核心功能：</p><h3 id="指令詳解" tabindex="-1"><a href="./cli-commands/">指令詳解</a> <a class="header-anchor" href="#指令詳解" aria-label="Permalink to &quot;[指令詳解](./cli-commands/)&quot;">​</a></h3><p>完整介紹所有 7 個指令、參數和標誌，提供指令速查表。適合需要快速查找指令用法的用戶。</p><h3 id="安裝來源詳解" tabindex="-1"><a href="./install-sources/">安裝來源詳解</a> <a class="header-anchor" href="#安裝來源詳解" aria-label="Permalink to &quot;[安裝來源詳解](./install-sources/)&quot;">​</a></h3><p>詳細講解三種安裝來源：GitHub 儲存庫、本地路徑、私有 Git 儲存庫。每種方式的適用場景、指令格式和注意事項。</p><h3 id="全域安裝-vs-專案本地安裝" tabindex="-1"><a href="./global-vs-project/">全域安裝 vs 專案本地安裝</a> <a class="header-anchor" href="#全域安裝-vs-專案本地安裝" aria-label="Permalink to &quot;[全域安裝 vs 專案本地安裝](./global-vs-project/)&quot;">​</a></h3><p>解釋 <code>--global</code> 和預設（專案本地）安裝的區別，幫助你選擇合適的安裝位置，理解技能搜尋優先順序規則。</p><h3 id="列出已安裝技能" tabindex="-1"><a href="./list-skills/">列出已安裝技能</a> <a class="header-anchor" href="#列出已安裝技能" aria-label="Permalink to &quot;[列出已安裝技能](./list-skills/)&quot;">​</a></h3><p>教會你使用 <code>list</code> 指令查看已安裝技能，理解 <code>(project)</code> 和 <code>(global)</code> 位置標籤的含義。</p><h3 id="更新技能" tabindex="-1"><a href="./update-skills/">更新技能</a> <a class="header-anchor" href="#更新技能" aria-label="Permalink to &quot;[更新技能](./update-skills/)&quot;">​</a></h3><p>指導你使用 <code>update</code> 指令重新整理已安裝技能，支援全部更新和指定技能更新，保持技能與來源儲存庫同步。</p><h3 id="刪除技能" tabindex="-1"><a href="./remove-skills/">刪除技能</a> <a class="header-anchor" href="#刪除技能" aria-label="Permalink to &quot;[刪除技能](./remove-skills/)&quot;">​</a></h3><p>介紹兩種刪除方式：互動式 <code>manage</code> 指令和腳本化 <code>remove</code> 指令，幫助你高效管理技能庫。</p><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><p>根據你的需求，選擇合適的學習路徑：</p><h3 id="路徑-a-系統學習-推薦新手" tabindex="-1">路徑 A：系統學習（推薦新手） <a class="header-anchor" href="#路徑-a-系統學習-推薦新手" aria-label="Permalink to &quot;路徑 A：系統學習（推薦新手）&quot;">​</a></h3><p>按順序學習所有內容，建立完整的知識體系：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>指令詳解 → 安裝來源 → 全域 vs 專案 → 列出技能 → 更新技能 → 刪除技能</span></span></code></pre></div><h3 id="路徑-b-按需查閱" tabindex="-1">路徑 B：按需查閱 <a class="header-anchor" href="#路徑-b-按需查閱" aria-label="Permalink to &quot;路徑 B：按需查閱&quot;">​</a></h3><p>根據當前任務直接跳轉：</p><table tabindex="0"><thead><tr><th>你想做什麼</th><th>閱讀這篇</th></tr></thead><tbody><tr><td>查找某個指令的用法</td><td><a href="./cli-commands/">指令詳解</a></td></tr><tr><td>從私有儲存庫安裝技能</td><td><a href="./install-sources/">安裝來源詳解</a></td></tr><tr><td>決定安裝到全域還是專案</td><td><a href="./global-vs-project/">全域 vs 專案</a></td></tr><tr><td>查看已安裝了哪些技能</td><td><a href="./list-skills/">列出已安裝技能</a></td></tr><tr><td>更新技能到最新版本</td><td><a href="./update-skills/">更新技能</a></td></tr><tr><td>清理不用的技能</td><td><a href="./remove-skills/">刪除技能</a></td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節後，你已經掌握了 OpenSkills 的日常使用技能。接下來可以：</p><ul><li><strong><a href="./../advanced/">進階功能</a></strong>：學習 Universal 模式、自訂輸出路徑、符號連結、建立自訂技能等進階功能</li><li><strong><a href="./../faq/">常見問題</a></strong>：遇到問題時查閱 FAQ 和故障排除指南</li></ul>',29)])])}const b=e(s,[["render",i]]);export{u as __pageData,b as default};
